INSERT INTO `tb_question` (`id`, `subject_id`, `type`, `content`, `options`, `answer`, `analysis`, `difficulty`, `tags`, `create_time`, `source`, `book_id`) VALUES (1047, 4011, 1, '设随机变量 $X \\sim B(n, p)$，且 $E(X)=2.4, D(X)=1.44$，则 parameters 为', '["A. $n=4, p=0.6$", "B. $n=6, p=0.4$", "C. $n=8, p=0.3$", "D. $n=24, p=0.1$"]', 'B', '$E(X)=np=2.4, D(X)=np(1-p)=1.44 \\Rightarrow 1-p = \\frac{1.44}{2.4} = 0.6 \\Rightarrow p=0.4 \\Rightarrow n=6$。', 3, '["数学", "真题", "模拟"]', NOW(), '智能生成模拟题', 1);
