INSERT INTO `tb_question` (`id`, `subject_id`, `type`, `content`, `options`, `answer`, `analysis`, `difficulty`, `tags`, `create_time`, `source`, `book_id`) VALUES (1060, 4013, 1, '求极限 $\\lim_{x \\to 0} \\frac{\\sin x - x}{x^3}$', '["A. $-\\\\frac{1}{6}$", "B. $\\\\frac{1}{6}$", "C. $0$", "D. $\\\\infty$"]', 'A', '由泰勒公式 $\\sin x = x - \\frac{x^3}{3!} + o(x^3)$，原式 $= \\lim_{x \\to 0} \\frac{-\\frac{x^3}{6}}{x^3} = -\\frac{1}{6}$。', 3, '["数学", "真题", "模拟"]', NOW(), '智能生成模拟题', 1);
INSERT INTO `tb_question_subject` (`question_id`, `subject_id`) VALUES (1060, 4013);
INSERT INTO `tb_question` (`id`, `subject_id`, `type`, `content`, `options`, `answer`, `analysis`, `difficulty`, `tags`, `create_time`, `source`, `book_id`) VALUES (1061, 702, 1, '下列关于栈的叙述中，正确的是', '["A. 栈顶元素一定是最先入栈的元素", "B. 栈操作遵循先进后出原则", "C. 栈底元素最后入栈", "D. 以上都不对"]', 'B', '栈（Stack）是限定仅在表尾进行插入和删除操作的线性表，遵循LIFO（Last In First Out）原则。', 3, '["408", "基础", "必刷"]', NOW(), '智能生成模拟题', 1);
INSERT INTO `tb_question_subject` (`question_id`, `subject_id`) VALUES (1061, 702);
INSERT INTO `tb_question` (`id`, `subject_id`, `type`, `content`, `options`, `answer`, `analysis`, `difficulty`, `tags`, `create_time`, `source`, `book_id`) VALUES (1062, 4011, 1, '若矩阵 $A = \\begin{pmatrix} 1 & 2 \\\\ 3 & 4 \\end{pmatrix}$，则 $A^T = $ ?', '["A. $\\\\begin{pmatrix} 1 & 3 \\\\\\\\ 2 & 4 \\\\end{pmatrix}$", "B. $\\\\begin{pmatrix} 4 & 3 \\\\\\\\ 2 & 1 \\\\end{pmatrix}$", "C. $\\\\begin{pmatrix} 1 & 2 \\\\\\\\ 3 & 4 \\\\end{pmatrix}$", "D. $\\\\begin{pmatrix} 4 & -2 \\\\\\\\ -3 & 1 \\\\end{pmatrix}$"]', 'A', '矩阵转置即行列互换。', 3, '["数学", "真题", "模拟"]', NOW(), '智能生成模拟题', 1);
INSERT INTO `tb_question_subject` (`question_id`, `subject_id`) VALUES (1062, 4011);
INSERT INTO `tb_question` (`id`, `subject_id`, `type`, `content`, `options`, `answer`, `analysis`, `difficulty`, `tags`, `create_time`, `source`, `book_id`) VALUES (1063, 704, 1, 'CPU 响应中断的时间是在', '["A. 一条指令执行结束时", "B. 一个机器周期结束时", "C. 一个时钟周期结束时", "D. 程序执行结束时"]', 'A', 'CPU通常在一条指令执行完毕后，检查是否有中断请求。', 3, '["408", "基础", "必刷"]', NOW(), '智能生成模拟题', 1);
