INSERT INTO `tb_question_subject` (`question_id`, `subject_id`) VALUES (1064, 703);
INSERT INTO `tb_question` (`id`, `subject_id`, `type`, `content`, `options`, `answer`, `analysis`, `difficulty`, `tags`, `create_time`, `source`, `book_id`) VALUES (1065, 4022, 1, '设 $f(x) = \\ln(1+x^2)$，则 $f''(1) = $ ?', '["A. $1$", "B. $\\\\frac{1}{2}$", "C. $2$", "D. $0$"]', 'A', '$f''(x) = \\frac{1}{1+x^2} \\cdot 2x = \\frac{2x}{1+x^2}$，代入 $x=1$ 得 $1$。', 3, '["数学", "真题", "模拟"]', NOW(), '智能生成模拟题', 1);
INSERT INTO `tb_question_subject` (`question_id`, `subject_id`) VALUES (1065, 4022);
INSERT INTO `tb_question` (`id`, `subject_id`, `type`, `content`, `options`, `answer`, `analysis`, `difficulty`, `tags`, `create_time`, `source`, `book_id`) VALUES (1066, 701, 1, '进程从运行态转换为就绪态的原因可能是', '["A. 等待I/O操作完成", "B. 时间片用完", "C. 进程执行完毕", "D. 进程被创建"]', 'B', '运行态 -> 就绪态通常是因为时间片耗尽或被更高优先级抢占；运行 -> 阻塞是等待事件；运行 -> 终止是结束。', 3, '["408", "基础", "必刷"]', NOW(), '智能生成模拟题', 1);
