INSERT INTO `tb_question` (`id`, `subject_id`, `type`, `content`, `options`, `answer`, `analysis`, `difficulty`, `tags`, `create_time`, `source`, `book_id`) VALUES (1067, 4011, 1, '设 $A, B$ 为 $n$ 阶矩阵，且 $(A+B)^2 = A^2 + 2AB + B^2$，则必有', '["A. $A=B$", "B. $AB=BA$", "C. $A=E$", "D. $B=E$"]', 'B', '$(A+B)^2 = (A+B)(A+B) = A^2 + AB + BA + B^2$，若等于 $A^2 + 2AB + B^2$，则需 $AB+BA = 2AB \\Rightarrow AB=BA$。', 3, '["数学", "真题", "模拟"]', NOW(), '智能生成模拟题', 1);
