INSERT INTO `tb_question` (`id`, `subject_id`, `type`, `content`, `options`, `answer`, `analysis`, `difficulty`, `tags`, `create_time`, `source`, `book_id`) VALUES (1090, 4031, 1, '若矩阵 $A = \\begin{pmatrix} 1 & 2 \\\\ 3 & 4 \\end{pmatrix}$，则 $A^T = $ ?', '["A. $\\\\begin{pmatrix} 1 & 3 \\\\\\\\ 2 & 4 \\\\end{pmatrix}$", "B. $\\\\begin{pmatrix} 4 & 3 \\\\\\\\ 2 & 1 \\\\end{pmatrix}$", "C. $\\\\begin{pmatrix} 1 & 2 \\\\\\\\ 3 & 4 \\\\end{pmatrix}$", "D. $\\\\begin{pmatrix} 4 & -2 \\\\\\\\ -3 & 1 \\\\end{pmatrix}$"]', 'A', '矩阵转置即行列互换。', 3, '["数学", "真题", "模拟"]', NOW(), '智能生成模拟题', 1);
INSERT INTO `tb_question_subject` (`question_id`, `subject_id`) VALUES (1090, 4031);
INSERT INTO `tb_question` (`id`, `subject_id`, `type`, `content`, `options`, `answer`, `analysis`, `difficulty`, `tags`, `create_time`, `source`, `book_id`) VALUES (1091, 703, 1, '下列关于栈的叙述中，正确的是', '["A. 栈顶元素一定是最先入栈的元素", "B. 栈操作遵循先进后出原则", "C. 栈底元素最后入栈", "D. 以上都不对"]', 'B', '栈（Stack）是限定仅在表尾进行插入和删除操作的线性表，遵循LIFO（Last In First Out）原则。', 3, '["408", "基础", "必刷"]', NOW(), '智能生成模拟题', 1);
INSERT INTO `tb_question_subject` (`question_id`, `subject_id`) VALUES (1091, 703);
INSERT INTO `tb_question` (`id`, `subject_id`, `type`, `content`, `options`, `answer`, `analysis`, `difficulty`, `tags`, `create_time`, `source`, `book_id`) VALUES (1092, 703, 1, '在OSI参考模型中，负责提供端到端传输的是', '["A. 网络层", "B. 传输层", "C. 会话层", "D. 应用层"]', 'B', '传输层（Transport Layer）的主要功能是为端到端连接提供可靠的传输服务。', 3, '["408", "基础", "必刷"]', NOW(), '智能生成模拟题', 1);
INSERT INTO `tb_question_subject` (`question_id`, `subject_id`) VALUES (1092, 703);
INSERT INTO `tb_question` (`id`, `subject_id`, `type`, `content`, `options`, `answer`, `analysis`, `difficulty`, `tags`, `create_time`, `source`, `book_id`) VALUES (1093, 4011, 1, '设 $A, B$ 为 $n$ 阶矩阵，且 $(A+B)^2 = A^2 + 2AB + B^2$，则必有', '["A. $A=B$", "B. $AB=BA$", "C. $A=E$", "D. $B=E$"]', 'B', '$(A+B)^2 = (A+B)(A+B) = A^2 + AB + BA + B^2$，若等于 $A^2 + 2AB + B^2$，则需 $AB+BA = 2AB \\Rightarrow AB=BA$。', 3, '["数学", "真题", "模拟"]', NOW(), '智能生成模拟题', 1);
INSERT INTO `tb_question_subject` (`question_id`, `subject_id`) VALUES (1093, 4011);
INSERT INTO `tb_question` (`id`, `subject_id`, `type`, `content`, `options`, `answer`, `analysis`, `difficulty`, `tags`, `create_time`, `source`, `book_id`) VALUES (1094, 4031, 1, '设随机变量 $X \\sim B(n, p)$，且 $E(X)=2.4, D(X)=1.44$，则 parameters 为', '["A. $n=4, p=0.6$", "B. $n=6, p=0.4$", "C. $n=8, p=0.3$", "D. $n=24, p=0.1$"]', 'B', '$E(X)=np=2.4, D(X)=np(1-p)=1.44 \\Rightarrow 1-p = \\frac{1.44}{2.4} = 0.6 \\Rightarrow p=0.4 \\Rightarrow n=6$。', 3, '["数学", "真题", "模拟"]', NOW(), '智能生成模拟题', 1);
INSERT INTO `tb_question_subject` (`question_id`, `subject_id`) VALUES (1094, 4031);
