INSERT INTO `tb_question` (`id`, `subject_id`, `type`, `content`, `options`, `answer`, `analysis`, `difficulty`, `tags`, `create_time`, `source`, `book_id`) VALUES (1097, 4012, 1, '设 $f(x) = \\ln(1+x^2)$，则 $f''(1) = $ ?', '["A. $1$", "B. $\\\\frac{1}{2}$", "C. $2$", "D. $0$"]', 'A', '$f''(x) = \\frac{1}{1+x^2} \\cdot 2x = \\frac{2x}{1+x^2}$，代入 $x=1$ 得 $1$。', 3, '["数学", "真题", "模拟"]', NOW(), '智能生成模拟题', 1);
INSERT INTO `tb_question_subject` (`question_id`, `subject_id`) VALUES (1097, 4012);
